+    info.protocols = protocols;
+    info.gid = -1;
+    info.uid = -1;
+    info.pt_serv_buf_size = 4096;
+    std::unique_ptr<Network> network(new Network);
+
+    network->context = lws_create_context(&info);
+
+    Initialize();
+
+#if 0
