+/* ---------------------------------------------------------------------------
+ * UVC Request processing
+ */
+
+static void uvc_fill_streaming_control(struct uvc_device *dev,
+                                       struct uvc_streaming_control *ctrl,
+                                       int iframe, int iformat) {
+    const struct uvc_format_info *format;
+    const struct uvc_frame_info *frame;
+    unsigned int nframes;
+
+    if (iformat < 0)
+        iformat = ARRAY_SIZE(uvc_formats) + iformat;
+    if (iformat < 0 || iformat >= (int)ARRAY_SIZE(uvc_formats))
+        return;
+    format = &uvc_formats[iformat];
+
+    nframes = 0;
+    while (format->frames[nframes].width != 0)
+        ++nframes;
+
+    if (iframe < 0)
+        iframe = nframes + iframe;
+    if (iframe < 0 || iframe >= (int)nframes)
+        return;
+    frame = &format->frames[iframe];
+
+    memset(ctrl, 0, sizeof *ctrl);
+
+    ctrl->bmHint = 1;
+    ctrl->bFormatIndex = iformat + 1;
+    ctrl->bFrameIndex = iframe + 1;
+    ctrl->dwFrameInterval = frame->intervals[0];
+    switch (format->fcc) {
+    case V4L2_PIX_FMT_YUYV:
+        ctrl->dwMaxVideoFrameSize = frame->width * frame->height * 2;
+        break;
+    case V4L2_PIX_FMT_MJPEG:
+        ctrl->dwMaxVideoFrameSize = dev->imgsize;
+        break;
+    }
+
+    /* TODO: the UVC maxpayload transfer size should be filled
+     * by the driver.
+     */
+    if (!dev->bulk)
+        ctrl->dwMaxPayloadTransferSize =
+            (dev->maxpkt) * (dev->mult + 1) * (dev->burst + 1);
+    else
+        ctrl->dwMaxPayloadTransferSize = ctrl->dwMaxVideoFrameSize;
+
+    ctrl->bmFramingInfo = 3;
+    ctrl->bPreferedVersion = 1;
+    ctrl->bMaxVersion = 1;
+}
+
+static void uvc_events_process_standard(struct uvc_device *dev,
+                                        struct usb_ctrlrequest *ctrl,
+                                        struct uvc_request_data *resp) {
+    printf("standard request\n");
+    (void)dev;
+    (void)ctrl;
+    (void)resp;
+}
+
+static void uvc_events_process_control(struct uvc_device *dev, uint8_t req,
+                                       uint8_t cs, uint8_t entity_id,
+                                       uint8_t len,
+                                       struct uvc_request_data *resp) {
+    switch (entity_id) {
+    case 0:
+        switch (cs) {
+        case UVC_VC_REQUEST_ERROR_CODE_CONTROL:
+            /* Send the request error code last prepared. */
+            resp->data[0] = dev->request_error_code.data[0];
+            resp->length = dev->request_error_code.length;
+            break;
+
+        default:
+            /*
+             * If we were not supposed to handle this
+             * 'cs', prepare an error code response.
+             */
+            SET_REQ_ERROR_CODE(0x06, 1);
+            break;
+        }
+        break;
+
+    /* Camera terminal unit 'UVC_VC_INPUT_TERMINAL'. */
+    case 1:
+        SET_REQ_ERROR_CODE(0x00, 1);
+        switch (cs) {
+        /*
+         * We support only 'UVC_CT_AE_MODE_CONTROL' for CAMERA
+         * terminal, as our bmControls[0] = 2 for CT. Also we
+         * support only auto exposure.
+         */
+        case UVC_CT_AE_MODE_CONTROL:
+            switch (req) {
+            case UVC_SET_CUR:
+                USB_REQ_DEBUG("Received SET_CUR %d\n", cs);
+
+                /* Incase of auto exposure, attempts to
+                 * programmatically set the auto-adjusted
+                 * controls are ignored.
+                 */
+                resp->data[0] = 0x01;
+                resp->length = 1;
+                break;
+
+            case UVC_GET_INFO:
+                /*
+                 * TODO: We support Set and Get requests, but
+                 * don't support async updates on an video
+                 * status (interrupt) endpoint as of
+                 * now.
+                 */
+                USB_REQ_DEBUG("Received GET_INFO %d\n", cs);
+
+                resp->data[0] = 0x03;
+                resp->length = 1;
+                break;
+
+            case UVC_GET_CUR:
+            case UVC_GET_DEF:
+            case UVC_GET_RES:
+                USB_REQ_DEBUG("Received %x on %d\n", req, cs);
+
+                /* Auto Mode â€“ auto Exposure Time, auto Iris. */
+                resp->data[0] = 0x02;
+                resp->length = 1;
+                break;
+            default:
+                USB_REQ_DEBUG("Unsupported: Received %x on %d\n", req, cs);
+
+                /*
+                 * We don't support this control, so STALL the
+                 * control ep.
+                 */
+                resp->length = -EL2HLT;
+                /*
+                 * For every unsupported control request
+                 * set the request error code to appropriate
+                 * value.
+                 */
+                SET_REQ_ERROR_CODE(0x07, 1);
+                break;
+            }
+            break;
+
+        default:
+            /*
+             * We don't support this control, so STALL the control
+             * ep.
+             */
+            resp->length = -EL2HLT;
+            /*
+             * If we were not supposed to handle this
+             * 'cs', prepare a Request Error Code response.
+             */
+            SET_REQ_ERROR_CODE(0x06, 1);
+            break;
+        }
+        break;
+
+    /* processing unit 'UVC_VC_PROCESSING_UNIT' */
+    case 2:
+        SET_REQ_ERROR_CODE(0x00, 1);
+        switch (cs) {
+        /*
+         * We support only 'UVC_PU_BRIGHTNESS_CONTROL' for Processing
+         * Unit, as our bmControls[0] = 1 for PU.
+         */
+        case UVC_PU_BRIGHTNESS_CONTROL:
+            switch (req) {
+            case UVC_SET_CUR:
+                resp->data[0] = 0x0;
+                resp->length = len;
+                break;
+            case UVC_GET_MIN:
+                resp->data[0] = PU_BRIGHTNESS_MIN_VAL;
+                resp->length = 2;
+                break;
+            case UVC_GET_MAX:
+                resp->data[0] = PU_BRIGHTNESS_MAX_VAL;
+                resp->length = 2;
+                break;
+            case UVC_GET_CUR:
+                resp->length = 2;
+                memcpy(&resp->data[0], &dev->brightness_val, resp->length);
+                break;
+            case UVC_GET_INFO:
+                /*
+                 * We support Set and Get requests and don't
+                 * support async updates on an interrupt endpt
+                 */
+                resp->data[0] = 0x03;
+                resp->length = 1;
+                break;
+            case UVC_GET_DEF:
+                resp->data[0] = PU_BRIGHTNESS_DEFAULT_VAL;
+                resp->length = 2;
+                break;
+            case UVC_GET_RES:
+                resp->data[0] = PU_BRIGHTNESS_STEP_SIZE;
+                resp->length = 2;
+                break;
+            default:
+                /*
+                 * We don't support this control, so STALL the
+                 * default control ep.
+                 */
+                resp->length = -EL2HLT;
+                /*
+                 * For every unsupported control request
+                 * set the request error code to appropriate
+                 * code.
+                 */
+                SET_REQ_ERROR_CODE(0x07, 1);
+                break;
+            }
+            break;
+
+        default:
+            /*
+             * We don't support this control, so STALL the control
+             * ep.
+             */
+            resp->length = -EL2HLT;
+            /*
+             * If we were not supposed to handle this
+             * 'cs', prepare a Request Error Code response.
+             */
+            SET_REQ_ERROR_CODE(0x06, 1);
+            break;
+        }
+
+        break;
+
+    /* extension unit 'UVC_VC_EXTENSION_UNIT' */
+    case 3:
+        SET_REQ_ERROR_CODE(0x00, 1);
+        switch (cs) {
+        case 1: /* AFE Programming */
+        case 2: /* AFE Register Read */
+            switch (req) {
+            case UVC_SET_CUR:
+                USB_REQ_DEBUG("Received SET_CUR on %d\n", cs);
+
+                dev->set_cur_cs = cs;
+                resp->data[0] = 0x0;
+                resp->length = len;
+                break;
+            case UVC_GET_CUR:
+                USB_REQ_DEBUG("Received GET_CUR on %d\n", cs);
+
+                if (cs == 2) {
+                    camDepthSensor->readAfeRegisters(
+                        &reg_addr,
+                        reinterpret_cast<unsigned short *>(resp->data), 1);
+                    resp->length = 2;
+                } else {
+                    resp->length = 2;
+                    memcpy(&resp->data[0], &dev->brightness_val, resp->length);
+                }
+                break;
+
+            case UVC_GET_INFO:
+                USB_REQ_DEBUG("Received GET_INFO on %d\n", cs);
+
+                /*
+                 * We support Set and Get requests and don't
+                 * support async updates on an interrupt endpt
+                 */
+                resp->data[0] = 0x03;
+                resp->length = 1;
+                break;
+            case UVC_GET_LEN:
+                USB_REQ_DEBUG("Received GET_LEN on %d\n", cs);
+
+                if (cs == 2) {
+                    resp->data[0] = 0x02; // 2 bytes
+                    resp->data[1] = 0x00;
+
+                    USB_REQ_DEBUG("Responding with size %x for cs: %d\n",
+                                  resp->data[0], cs);
+                } else {
+                    resp->data[0] = MAX_PACKET_SIZE; // 60 bytes
+                    resp->data[1] = 0x00;
+
+                    USB_REQ_DEBUG("Responding with size %x for cs: %d\n",
+                                  resp->data[0], cs);
+                }
+                resp->length = 2;
+                break;
+
+            case UVC_GET_MIN:
+            case UVC_GET_MAX:
+            case UVC_GET_DEF:
+            case UVC_GET_RES:
+                USB_REQ_DEBUG("Received %x on %d\n", req, cs);
+
+                resp->data[0] = 0xff;
+                resp->length = 1;
+                break;
+
+            default:
+                printf("Unsupported bRequest: Received bRequest %x on cs %d\n",
+                       req, cs);
+                /*
+                 * We don't support this control, so STALL the
+                 * default control ep.
+                 */
+                resp->length = -EL2HLT;
+                /*
+                 * For every unsupported control request
+                 * set the request error code to appropriate
+                 * code.
+                 */
+                SET_REQ_ERROR_CODE(0x07, 1);
+                break;
+            }
+            break;
+
+        case 3: /* TempSensor Read */
+            switch (req) {
+            case UVC_SET_CUR:
+                USB_REQ_DEBUG("Received SET_CUR on %d\n", cs);
+                dev->set_cur_cs = cs;
+                resp->data[0] = 0x0;
+                resp->length = len;
+                break;
+
+            case UVC_GET_CUR:
+                USB_REQ_DEBUG("Received GET_CUR on %d\n", cs);
+
+                float temperature;
+                temperatureSensors[temp_index]->read(temperature);
+                *((float *)resp->data) = temperature;
+                resp->length = 4;
+                break;
+
+            case UVC_GET_INFO:
+                USB_REQ_DEBUG("Received GET_INFO on %d\n", cs);
+
+                /*
+                 * We support Set and Get requests and don't
+                 * support async updates on an interrupt endpt
+                 */
+                resp->data[0] = 0x03;
+                resp->length = 1;
+                break;
+
+            case UVC_GET_LEN:
+                USB_REQ_DEBUG("Received GET_LEN on %d\n", cs);
+
+                resp->data[0] = 0x04; // 4 bytes
+                resp->data[1] = 0x00;
+                resp->length = 2;
+
+                USB_REQ_DEBUG("Responding with size %x for cs: %d\n",
+                              resp->data[0], cs);
+                break;
+
+            case UVC_GET_MIN:
+            case UVC_GET_MAX:
+            case UVC_GET_DEF:
+            case UVC_GET_RES:
+                USB_REQ_DEBUG("Received %x on %d\n", req, cs);
+
+                resp->data[0] = 0xff;
+                resp->length = 1;
+                break;
+
+            default:
+                printf("Unsupported bRequest: Received bRequest %x on cs %d\n",
+                       req, cs);
+                /*
+                 * We don't support this control, so STALL the
+                 * default control ep.
+                 */
+                resp->length = -EL2HLT;
+                /*
+                 * For every unsupported control request
+                 * set the request error code to appropriate
+                 * code.
+                 */
+                SET_REQ_ERROR_CODE(0x07, 1);
+                break;
+            }
+            break;
+
+        case 4: /* Get advertised sensors */
+            switch (req) {
+            case UVC_SET_CUR:
+                dev->set_cur_cs = cs;
+                resp->data[0] = 0x0;
+                resp->length = len;
+                break;
+
+            case UVC_GET_CUR:
+                memcpy(resp->data, sensorsInfoBuffer + sensors_read_pos,
+                       sensors_read_len);
+                resp->length = sensors_read_len;
+                break;
+
+            case UVC_GET_INFO:
+                /*
+                 * We support Set and Get requests and don't
+                 * support async updates on an interrupt endpt
+                 */
+                resp->data[0] = 0x03;
+                resp->length = 1;
+                break;
+
+            case UVC_GET_LEN:
+                resp->data[0] = MAX_PACKET_SIZE;
+                resp->data[1] = 0x0;
+                resp->length = 2;
+                break;
+            case UVC_GET_MIN:
+            case UVC_GET_MAX:
+            case UVC_GET_DEF:
+            case UVC_GET_RES:
+                USB_REQ_DEBUG("Received %x on %d\n", req, cs);
+
+                resp->data[0] = 0xff;
+                resp->length = 1;
+                break;
+            default:
+                printf("Unsupported bRequest: Received bRequest %x on cs %d\n",
+                       req, cs);
+                /*
+                 * We don't support this control, so STALL the
+                 * default control ep.
+                 */
+                resp->length = -EL2HLT;
+                /*
+                 * For every unsupported control request
+                 * set the request error code to appropriate
+                 * code.
+                 */
+                SET_REQ_ERROR_CODE(0x07, 1);
+                break;
+            } //switch (req)
+            break;
+
+        case 5: /* EEPROM Read */
+        case 6: /* EEPROM Write */
+            switch (req) {
+            case UVC_SET_CUR:
+                USB_REQ_DEBUG("Received SET_CUR on %d\n", cs);
+                dev->set_cur_cs = cs;
+
+                resp->data[0] = 0x0;
+                resp->length = len;
+                break;
+
+            case UVC_GET_CUR:
+                USB_REQ_DEBUG("Received GET_CUR on %d\n", cs);
+
+                if (cs == 5) {
+                    storages[storage_index]->read(eeprom_read_addr, resp->data,
+                                                  eeprom_read_len);
+                    resp->length = eeprom_read_len;
+                }
+                break;
+
+            case UVC_GET_INFO:
+                USB_REQ_DEBUG("Received GET_INFO on %d\n", cs);
+
+                /*
+                 * We support Set and Get requests and don't
+                 * support async updates on an interrupt endpt
+                 */
+                resp->data[0] = 0x03;
+                resp->length = 1;
+                break;
+
+            case UVC_GET_LEN:
+                USB_REQ_DEBUG("Received GET_LEN on %d\n", cs);
+
+                if (cs == 6 || cs == 5) {
+                    resp->data[0] = MAX_PACKET_SIZE; // 2 bytes
+                } else {
+                    resp->data[0] = 0x02; // 2 bytes
+                }
+                resp->data[1] = 0x00;
+                resp->length = 2;
+
+                USB_REQ_DEBUG("Responding with size %x for cs: %d\n",
+                              resp->data[0], cs);
+                break;
+
+            case UVC_GET_MIN:
+            case UVC_GET_MAX:
+            case UVC_GET_DEF:
+            case UVC_GET_RES:
+                USB_REQ_DEBUG("Received %x on %d\n", req, cs);
+
+                resp->data[0] = 0xff;
+                resp->length = 1;
+                break;
+
+            default:
+                printf("Unsupported bRequest: Received bRequest %x on cs %d\n",
+                       req, cs);
+                /*
+                 * We don't support this control, so STALL the
+                 * default control ep.
+                 */
+                resp->length = -EL2HLT;
+                /*
+                 * For every unsupported control request
+                 * set the request error code to appropriate
+                 * code.
+                 */
+                SET_REQ_ERROR_CODE(0x07, 1);
+                break;
+            }
+            break;
+
+        case 7: /* Ready for writing to EEPROM */
+            switch (req) {
+            case UVC_SET_CUR:
+                resp->data[0] = 0x0;
+                resp->length = len;
+                break;
+
+            case UVC_GET_CUR:
+                resp->data[0] = eeprom_write_ready.load() ? 1 : 0;
+                resp->length = 1;
+                break;
+
+            case UVC_GET_INFO:
+                /*
+                 * We support Set and Get requests and don't
+                 * support async updates on an interrupt endpt
+                 */
+                resp->data[0] = 0x03;
+                resp->length = 1;
+                break;
+
+            case UVC_GET_LEN:
+                resp->data[0] = 0x01; // 1 byte
+                resp->data[1] = 0x00;
+                resp->length = 2;
+                break;
+
+            case UVC_GET_MIN:
+            case UVC_GET_MAX:
+            case UVC_GET_DEF:
+            case UVC_GET_RES:
+                resp->data[0] = 0xff;
+                resp->length = 1;
+                break;
+
+            default:
+                printf("Unsupported bRequest: Received bRequest %x on cs %d\n",
+                       req, cs);
+                /*
+                 * We don't support this control, so STALL the
+                 * default control ep.
+                 */
+                resp->length = -EL2HLT;
+                /*
+                 * For every unsupported control request
+                 * set the request error code to appropriate
+                 * code.
+                 */
+                SET_REQ_ERROR_CODE(0x07, 1);
+                break;
+            }
+            break;
+
+        default:
+            printf("Unsupported cs: Received cs %d \n", cs);
+            /*
+             * We don't support this control, so STALL the control
+             * ep.
+             */
+            resp->length = -EL2HLT;
+            /*
+             * If we were not supposed to handle this
+             * 'cs', prepare a Request Error Code response.
+             */
+            SET_REQ_ERROR_CODE(0x06, 1);
+            break;
+        }
+
+        break;
+
+    default:
+        printf("Unsupported entity: Reeived control on invalid entity id %d\n",
+               entity_id);
+        /*
+         * If we were not supposed to handle this
+         * 'cs', prepare a Request Error Code response.
+         */
+        SET_REQ_ERROR_CODE(0x06, 1);
+        break;
+    }
+
+    // printf("control request (req %02x cs %02x)\n", req, cs);
+}
