+    int baseLine;
+    Size labelSize =
+        getTextSize(label, FONT_HERSHEY_SIMPLEX, 0.5, 1, &baseLine);
+    rectangle(
+        image,
+        Point(10, image.rows - 10 - labelSize.height - int(baseLine * 0.5)),
+        Point(10 + labelSize.width, image.rows - 10 + baseLine),
