++		msleep(5);
++
++		memset(header_packet, 0, sizeof(header_packet));
++		memset(data_packet, 0, PAYLOAD_MAX_CHUNK_SIZE * sizeof(uint8_t));
++		position=0;
++		curr_segment++;
