+  double k[14] = {k1, k2, p1, p2, k3, k4, k5, k6, 0, 0, 0, 0, 0, 0};
+
+  double fx = _cameraMatrix->fx / row_bin_factor;
+  double fy = _cameraMatrix->fy / col_bin_factor;
+
+  double ifx = 1. / fx;
+  double ify = 1. / fy;
+  double cx = _cameraMatrix->cx / row_bin_factor;
+  double cy = _cameraMatrix->cy / col_bin_factor;
+
+  int n = rows * cols;
+  for (int i = 0; i < n; i++) {
+    double x, y, x0 = 0, y0 = 0, u, v;
+
+    x = _srcx[i];
+    y = _srcy[i];
+
+    u = x;
+    v = y;
+    x = (x - cx) * ifx;
+    y = (y - cy) * ify;
+
+    // if (_distCoeffs) {
+    // compensate tilt distortion
+
+    x0 = x;
+    y0 = y;
+
+    // compensate distortion iteratively
+
+    for (int j = 0; j < maxcount; j++) {
+      double r2 = x * x + y * y;
+      double icdist = (1 + ((k[7] * r2 + k[6]) * r2 + k[5]) * r2) /
+                      (1 + ((k[4] * r2 + k[1]) * r2 + k[0]) * r2);
+      if (icdist < 0)  // test: undistortPoints.regression_14583
+      {
+        x = (u - cx) * ifx;
+        y = (v - cy) * ify;
+        break;
+      }
+      double deltaX = 2 * k[2] * x * y + k[3] * (r2 + 2 * x * x) + k[8] * r2 +
+                      k[9] * r2 * r2;
+      double deltaY = k[2] * (r2 + 2 * y * y) + 2 * k[3] * x * y + k[10] * r2 +
+                      k[11] * r2 * r2;
+      x = (x0 - deltaX) * icdist;
+      y = (y0 - deltaY) * icdist;
+    }
+    _dstx[i] = (float)x;
+    _dsty[i] = (float)y;
+  }
+}
