+#ifdef COMPILE_GLOB64
+		    d = convert_dirent (__readdir (stream));
+#else
+		    d = convert_dirent64 (__readdir64 (stream));
+#endif
+		  }
+	      }
+	      if (d.name == NULL)
+		break;
+	      if (d.skip_entry)
+		continue;
